import io
import os
import typing
from pathlib import Path

from ._types import (
    AsyncByteStream,
    FileContent,
    FileTypes,
    RequestData,
    RequestFiles,
    SyncByteStream,
)
from ._utils import (
    format_form_param,
    guess_content_type,
    peek_filelike_length,
    primitive_value_to_str,
    to_bytes,
)


def get_multipart_boundary_from_content_type(
    content_type: typing.Optional[bytes],
) -> typing.Optional[bytes]:
    """Extract a boundary parameter from a multipart/form-data Content-Type header.

    Args:
        content_type: The value of a Content-Type header as bytes.

    Returns:
        The boundary as bytes if present and the content type specifies
        multipart/form-data, otherwise None.
    """
    if not content_type or not content_type.startswith(b"multipart/form-data"):
        return None
    # parse boundary according to
    # https://www.rfc-editor.org/rfc/rfc2046#section-5.1.1
    if b";" in content_type:
        for section in content_type.split(b";"):
            if section.strip().lower().startswith(b"boundary="):
                return section.strip()[len(b"boundary=") :].strip(b'"')
    return None


class DataField:
    """
    A single form field item, within a multipart form field.
    """

    def __init__(
        self, name: str, value: typing.Union[str, bytes, int, float, None]
    ) -> None:
        """Initialize a DataField.

        Args:
            name: The form parameter name.
            value: A primitive value (str, bytes, int, float, or None).
        """
        if not isinstance(name, str):
            raise TypeError(
                f"Invalid type for name. Expected str, got {type(name)}: {name!r}"
            )
        if value is not None and not isinstance(value, (str, bytes, int, float)):
            raise TypeError(
                "Invalid type for value. Expected primitive type,"
                f" got {type(value)}: {value!r}"
            )
        self.name = name
        self.value: typing.Union[str, bytes] = (
            value if isinstance(value, bytes) else primitive_value_to_str(value)
        )

    def render_headers(self) -> bytes:
        """Render the headers for this data field (as bytes)."""
        if not hasattr(self, "_headers"):
            name = format_form_param("name", self.name)
            self._headers = b"".join(
                [b"Content-Disposition: form-data; ", name, b"\r\n\r\n"]
            )

        return self._headers

    def render_data(self) -> bytes:
        """Render the data payload for this field as bytes."""
        if not hasattr(self, "_data"):
            self._data = to_bytes(self.value)

        return self._data

    def get_length(self) -> int:
        """Return the total length in bytes of headers + data for this field."""
        headers = self.render_headers()
        data = self.render_data()
        return len(headers) + len(data)

    def render(self) -> typing.Iterator[bytes]:
        """Yield headers and data as bytes in sequence for this field."""
        yield self.render_headers()
        yield self.render_data()


class FileField:
    """
    A single file field item, within a multipart form field.
    """

    CHUNK_SIZE = 64 * 1024

    def __init__(self, name: str, value: FileTypes) -> None:
        """Initialize a FileField.

        The `value` may be one of:
          - a file-like object (with .read()), or
          - a tuple (filename, fileobj), (filename, fileobj, content_type),
            or (filename, fileobj, content_type, headers).

        Args:
            name: The form parameter name.
            value: The file value or tuple describing the file.
        """
        self.name = name

        fileobj: FileContent

        headers: typing.Dict[str, str] = {}
        content_type: typing.Optional[str] = None

        # This API mirrors requests' API: tuple of length 2, 3, or 4.
        if isinstance(value, tuple):
            if len(value) == 2:
                filename, fileobj = value  # type: ignore
            elif len(value) == 3:
                filename, fileobj, content_type = value  # type: ignore
            else:
                filename, fileobj, content_type, headers = value  # type: ignore
        else:
            filename = Path(str(getattr(value, "name", "upload"))).name
            fileobj = value

        if content_type is None:
            content_type = guess_content_type(filename)

        has_content_type_header = any("content-type" in key.lower() for key in headers)
        if content_type is not None and not has_content_type_header:
            headers = dict(headers)
            headers["Content-Type"] = content_type  # type: ignore

        self.filename = filename
        self.fileobj = fileobj
        self.headers = headers

        # Determine length if possible
        self._data_length: typing.Optional[int] = None
        if isinstance(fileobj, (bytes, bytearray)):
            self._data_length = len(fileobj)
        elif isinstance(fileobj, str):
            self._data_length = len(to_bytes(fileobj))
            # also convert to bytes when rendering
            self.fileobj = to_bytes(fileobj)
        else:
            # try to peek into file-like objects for length
            try:
                self._data_length = peek_filelike_length(fileobj)
            except Exception:
                self._data_length = None

    def get_length(self) -> typing.Optional[int]:
        """Return the total length in bytes of headers + data for this file field.

        Returns None if the length of the file data is not known.
        """
        headers = self.render_headers()
        if self._data_length is None:
            return None
        return len(headers) + self._data_length

    def render_headers(self) -> bytes:
        """Render the headers (Content-Disposition, and any provided headers)."""
        if not hasattr(self, "_headers_bytes"):
            disposition_name = format_form_param("name", self.name)
            disposition_filename = format_form_param("filename", self.filename)
            parts = [
                b"Content-Disposition: form-data; ",
                disposition_name,
                b"; ",
                disposition_filename,
                b"\r\n",
            ]
            for key, value in self.headers.items():
                parts.append(f"{key}: {value}\r\n".encode("utf-8"))
            parts.append(b"\r\n")
            self._headers_bytes = b"".join(parts)
        return self._headers_bytes

    def render_data(self) -> typing.Iterator[bytes]:
        """Yield the file data as a sequence of byte chunks."""
        if isinstance(self.fileobj, (bytes, bytearray)):
            yield bytes(self.fileobj)
        elif isinstance(self.fileobj, io.IOBase) or hasattr(self.fileobj, "read"):
            # It's a file-like object.
            fileobj = self.fileobj
            try:
                # Try to seek to start if it's a file with a tell/seek.
                if hasattr(fileobj, "seek") and hasattr(fileobj, "tell"):
                    try:
                        fileobj.seek(0)
                    except Exception:
                        pass
                chunk = fileobj.read(self.CHUNK_SIZE)
                while chunk:
                    if isinstance(chunk, str):
                        chunk = to_bytes(chunk)
                    yield chunk
                    chunk = fileobj.read(self.CHUNK_SIZE)
            finally:
                # Do not close the fileobj here; leave lifecycle to the caller.
                pass
        else:
            # Fallback: convert to bytes and yield once.
            yield to_bytes(self.fileobj)

    def render(self) -> typing.Iterator[bytes]:
        """Yield headers followed by file data chunks for this field."""
        yield self.render_headers()
        for chunk in self.render_data():
            yield chunk


class MultipartEncoder:
    """
    Encodes data and files into multipart/form-data byte chunks iterable.

    This class provides an iterator interface that yields bytes, suitable for
    streaming upload bodies.
    """

    def __init__(
        self,
        data: typing.Optional[RequestData] = None,
        files: typing.Optional[RequestFiles] = None,
        boundary: typing.Optional[bytes] = None,
    ) -> None:
        """Initialize a MultipartEncoder.

        Args:
            data: Mapping or sequence of form field name/value pairs.
            files: Mapping or sequence of file field name/value pairs.
            boundary: Optional bytes boundary to use; if not provided, one is generated.
        """
        self.data = data or {}
        self.files = files or {}
        if boundary is None:
            # Generate a reasonably unique boundary
            self.boundary = b"------------------------" + os.urandom(12).hex().encode()
        else:
            self.boundary = boundary

        # Pre-build fields list for deterministic ordering and reuse.
        self._fields: typing.List[typing.Union[DataField, FileField]] = list(
            self._iter_fields()
        )

    def _iter_fields(self) -> typing.Iterator[typing.Union[DataField, FileField]]:
        """Yield DataField and FileField objects from provided data and files.

        Supports mappings and sequences of pairs.
        """
        # Helper to iterate mapping or list-of-pairs
        def iter_pairs(obj: typing.Any):
            if obj is None:
                return
            if isinstance(obj, dict):
                for key, value in obj.items():
                    yield key, value
            else:
                for item in obj:
                    if isinstance(item, (list, tuple)) and len(item) == 2:
                        yield item[0], item[1]
                    else:
                        raise TypeError("Items must be 2-tuples (name, value)")

        # First yield data fields
        for name, value in iter_pairs(self.data):
            # Accept multiple values for same name if provided as list/tuple
            if isinstance(value, (list, tuple)):
                for v in value:
                    yield DataField(name, v)
            else:
                yield DataField(name, value)

        # Then yield file fields
        for name, value in iter_pairs(self.files):
            # files might be provided as a list of files under same name
            if isinstance(value, (list, tuple)) and not (
                isinstance(value[0], (str, bytes)) or hasattr(value[0], "read")
            ):
                # It's a sequence of file-tuples
                for v in value:
                    yield FileField(name, v)
            else:
                yield FileField(name, value)

    def iter_chunks(self) -> typing.Iterator[bytes]:
        """Yield the multipart body as a sequence of byte chunks.

        Each field is prefixed with the boundary and the final boundary is emitted.
        """
        boundary_line = b"--" + self.boundary + b"\r\n"
        boundary_close = b"--" + self.boundary + b"--\r\n"

        for field in self._fields:
            # boundary
            yield boundary_line
            # headers and data
            for part in field.render():
                yield part
            # trailing CRLF after each part
            yield b"\r\n"

        # final boundary
        yield boundary_close

    def get_length(self) -> typing.Optional[int]:
        """Attempt to compute and return the total Content-Length of the body.

        Returns None if any field has an unknown length (e.g., streaming file).
        """
        total: int = 0
        boundary_prefix = b"--" + self.boundary + b"\r\n"
        boundary_close = b"--" + self.boundary + b"--\r\n"
        # For each field: boundary + field.get_length() + CRLF
        for field in self._fields:
            field_len = field.get_length()
            if field_len is None:
                return None
            total += len(boundary_prefix)
            total += field_len
            total += len(b"\r\n")
        total += len(boundary_close)
        return total

    def get_headers(self) -> typing.Dict[str, str]:
        """Return headers appropriate for sending this multipart body.

        Includes Content-Type and, if computable, Content-Length.
        """
        headers: typing.Dict[str, str] = {}
        headers["Content-Type"] = f'multipart/form-data; boundary="{self.boundary.decode()}"'
        length = self.get_length()
        if length is not None:
            headers["Content-Length"] = str(length)
        return headers

    def __iter__(self) -> typing.Iterator[bytes]:
        """Return an iterator over the multipart byte chunks (compatibility with iter())."""
        return self.iter_chunks()